  ('social-worker-moex-03842', 'social-worker', 'social-worker-moex-112-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '依據學者Roberts和Yeager2009年的觀點，在災區為受災者搭建臨時祭祀處，提供香、紙錢等有 助其安定感的物品，是危機干預模式中那個階段的工作要點？', '["檢視問題範圍", "快速建立關係", "進行完善心理社會評量", "執行行動計畫恢復認知功能"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:22+00:00", "source_pdf_sha1": "b579889576bc", "answer_pdf_sha1": "1ccce4f000cb", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "103", "s": "0302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 6, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-03843', 'social-worker', 'social-worker-moex-112-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '有關社會個案工作不同階段的順序，下列何者正確？', '["調查、接案、診斷、處遇、結案、評估", "接案、調查、診斷、處遇、評估、結案", "接案、調查、診斷、處遇、結案、評估", "調查、診斷、接案、處遇、結案、評估"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:22+00:00", "source_pdf_sha1": "b579889576bc", "answer_pdf_sha1": "1ccce4f000cb", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "103", "s": "0302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 7, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-03844', 'social-worker', 'social-worker-moex-112-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '依據學者Kramer與Joyce等人的觀點，社會工作結束的成效反映在下列那幾項任務的完成狀態？', '["案主在處遇過程中所獲得的成果予以加強", "解決處遇關係中所產生的移情作用與結束分離 焦慮", "案主對於會談室以外行使與維持社會生活功能的準備與類化程度", "重新定義結案意 義以符合案主的發展需求"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:22+00:00", "source_pdf_sha1": "b579889576bc", "answer_pdf_sha1": "1ccce4f000cb", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "103", "s": "0302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 8, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-03845', 'social-worker', 'social-worker-moex-112-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '有關社會個案工作者在進行評量（assessment）時需具備「多元文化的能力」，下列何者錯誤？', '["社會工作者對自己所持觀點、對待案家方式和前述二者如何受到自身文化影響的覺察是培養多 元文化能力起點", "具備多元文化能力的工作者，除了會挑戰自身文化價值外，同時對他人行為表現和處境會抱持 較高的彈性", "培養多元文化能力的阻礙，往往不是來自個人，而是來自組織、政策和制度", "多元文化能力的培養旨在促使不同形態或不同特質文化之間的相互融合"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:22+00:00", "source_pdf_sha1": "b579889576bc", "answer_pdf_sha1": "1ccce4f000cb", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "103", "s": "0302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 9, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-03846', 'social-worker', 'social-worker-moex-112-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '有關結案後續追蹤階段作法，下列何者錯誤？', '["有助於確認處遇成效，鼓勵案主繼續努力", "工作者與案主會談互動上採取正式的形式", "提供短暫額外的協助，幫助案主面對仍有困難的部分", "執行過程要對案主因接觸帶來持續性依附關係保持警覺"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:22+00:00", "source_pdf_sha1": "b579889576bc", "answer_pdf_sha1": "1ccce4f000cb", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "103", "s": "0302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 10, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-03847', 'social-worker', 'social-worker-moex-112-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '面對沒有其他照顧資源而且被多次通報獨留的照顧者，只能再將多名年幼兒少單獨留在家中以出 門辦事的情境，下列陳述何者屬於社工員之中高層次的同理回應？', '["「我想你也知道法律有規定，任何人不得將6歲以下的兒少單獨留在家中或讓不適任者照顧， 所以，我幫你找臨托，好嗎？」", "「雖然我理解你的無奈，但你也知道這就是法律規定，沒辦法，你就是不可以把這麼小的孩子 丟在家裡啦！」", "「我想你應該已經知道不能把孩子留在家裡，可是卻一定得要出門辦事，這應該讓你覺得很為 難……看起來我們之前的計畫好像沒用？」", "「我想你鐵定覺得我們大驚小怪，孩子在家又不會怎麼樣……如果我是你，我可能也會這樣做……」"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:22+00:00", "source_pdf_sha1": "b579889576bc", "answer_pdf_sha1": "1ccce4f000cb", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "103", "s": "0302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 11, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-03848', 'social-worker', 'social-worker-moex-112-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '下列何者不屬於摘要回應（summarizingresponses）的目的？', '["改變討論焦點前，強調問題的重要面向", "確認個案的情緒狀態", "連結個案冗長的相關陳述", "承先啟後，提供會談的焦點以及會談間的連續性"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:22+00:00", "source_pdf_sha1": "b579889576bc", "answer_pdf_sha1": "1ccce4f000cb", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "103", "s": "0302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 12, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-03849', 'social-worker', 'social-worker-moex-112-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '下列何者不屬於紀錄的原則？', '["不論是否熟悉，儘可能使用專業術語，以凸顯專業性", "除非有特殊目的，不然紀錄以簡明扼要為原則，而且要避免太多的主觀評斷", "每次與案主或有關人員接觸時，都應將接觸時間、地點和內容紀錄下來", "每次會談內容都應該紀錄下來，以避免遺忘或混淆"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:22+00:00", "source_pdf_sha1": "b579889576bc", "answer_pdf_sha1": "1ccce4f000cb", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "103", "s": "0302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 13, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
